{
  mongo_msg_header header;
  int start = buf->pos - buf->start;

  php_printf("writing more\n");

There seem to be a couple of double frees in the mongo driver:

from collection.c:
     if (FAILURE == php_mongo_write_update(&buf, Z_STRVAL_P(c->ns), opts, criteria, newobj TSRMLS_CC)) {
-->    efree(buf.start);
       return;
     }

from bson.c:
     if (zval_to_bson(buf, HASH_P(criteria), NO_PREP TSRMLS_CC) == FAILURE ||
         zval_to_bson(buf, HASH_P(newobj), NO_PREP TSRMLS_CC) == FAILURE) {
-->    efree(buf->start);
       zend_throw_exception_ex(mongo_ce_Exception, 0 TSRMLS_CC, "non-utf8 string: %s", MonGlo(errmsg));  
       return FAILURE;
     }

So buf.start is already freed when there is a failure.

